{
  "title": "फ़ंक्शन्स के साथ मूव सेमेंटिक्स",
  "group": "ओनरशिप",
  "options": [
    {
      "text": "दोनों लाइनें प्रिंट होती हैं",
      "hint": "ध्यान दें कि फ़ंक्शन को पास करने के बाद `wisdom` का क्या होता है"
    },
    {
      "text": "केवल पहली लाइन प्रिंट होती है",
      "hint": "कोड रनटाइम तक पहुँचने के लिए कंपाइल भी नहीं होगा"
    },
    {
      "text": "कंपाइलेशन एरर"
    },
    {
      "text": "रनटाइम एरर",
      "hint": "Rust के ओनरशिप नियम कंपाइल टाइम पर लागू होते हैं"
    }
  ],
  "questionProse": [
    "जब आप इस कोड को चलाते हैं तो क्या होता है? ओनरशिप ट्रांसफर के बारे में सोचें:"
  ],
  "explanationProse": [
    "कोड कंपाइल होने में विफल रहता है क्योंकि `wisdom` की ओनरशिप `take_knowledge` में ट्रांसफर हो गई है, इसलिए इसका बाद में उपयोग नहीं किया जा सकता।\n\n      इस समस्या को ठीक करने के तीन तरीके हैं:\n\n      1. रेफरेंस द्वारा पास करें (वैल्यू को बॉरो करें):",
    "2. वैल्यू को क्लोन करें (एक नई कॉपी बनाएं):",
    "3. फ़ंक्शन से ओनरशिप वापस लौटाएं:",
    "हर तरीके के अलग-अलग उपयोग के मामले हैं:\n      - रेफरेंसेस: सबसे कुशल, लेकिन लाइफटाइम मैनेजमेंट की आवश्यकता होती है\n      - क्लोनिंग: सरल लेकिन संभावित रूप से महंगा\n      - ओनरशिप वापस लौटाना: वैल्यू को ट्रांसफॉर्म करने के लिए उपयोगी\n\n      बेस्ट प्रैक्टिस: जब तक आपको ओनरशिप ट्रांसफर की आवश्यकता न हो, रेफरेंसेस का उपयोग करें।"
  ]
}
